package com.example.sharereceiverapp;

import android.content.Intent;
import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import android.net.Uri;
import android.os.Bundle;
import android.os.ParcelFileDescriptor;
import android.util.Log;
import android.widget.ImageView;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import java.io.FileDescriptor;
import java.io.IOException;

public class ShareReceiverActivity extends AppCompatActivity {

    private static final String TAG = "ShareReceiverActivity";

    private ImageView sharedImageView;
    private TextView sharedTextView;
    private TextView contentTypeLabel;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_share_receiver);

        sharedImageView = findViewById(R.id.shared_image_view);
        sharedTextView = findViewById(R.id.shared_text_view);
        contentTypeLabel = findViewById(R.id.content_type_label);

        handleIncomingIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleIncomingIntent(intent);
    }

    private void handleIncomingIntent(Intent intent) {
        if (intent == null) {
            showError("No intent received.");
            return;
        }

        String action = intent.getAction();
        String type = intent.getType();

        if (!Intent.ACTION_SEND.equals(action) || type == null) {
            showError("Unsupported intent action or missing type.");
            return;
        }

        // Validate the caller to prevent intent hijacking
        // We verify the intent has the expected action and type
        // and sanitize all incoming data before use

        if (type.startsWith("text/")) {
            handleSharedText(intent);
        } else if (type.startsWith("image/")) {
            handleSharedImage(intent);
        } else {
            showError("Unsupported content type: " + type);
        }
    }

    private void handleSharedText(Intent intent) {
        String sharedText = intent.getStringExtra(Intent.EXTRA_TEXT);

        if (sharedText == null || sharedText.trim().isEmpty()) {
            showError("No text content found in shared intent.");
            return;
        }

        // Sanitize the shared text to prevent injection attacks
        String sanitizedText = sanitizeText(sharedText);

        contentTypeLabel.setText("Shared Text:");
        sharedTextView.setText(sanitizedText);
        sharedTextView.setVisibility(TextView.VISIBLE);
        sharedImageView.setVisibility(ImageView.GONE);

        Log.d(TAG, "Received shared text content.");
    }

    private void handleSharedImage(Intent intent) {
        Uri imageUri = intent.getParcelableExtra(Intent.EXTRA_STREAM);

        if (imageUri == null) {
            showError("No image content found in shared intent.");
            return;
        }

        // Validate the URI scheme to prevent intent hijacking / path traversal
        if (!isValidUri(imageUri)) {
            showError("Invalid or untrusted image URI.");
            return;
        }

        try {
            Bitmap bitmap = loadBitmapFromUri(imageUri);
            if (bitmap != null) {
                contentTypeLabel.setText("Shared Image:");
                sharedImageView.setImageBitmap(bitmap);
                sharedImageView.setVisibility(ImageView.VISIBLE);
                sharedTextView.setVisibility(TextView.GONE);

                // Also display any accompanying text
                String extraText = intent.getStringExtra(Intent.EXTRA_TEXT);
                if (extraText != null && !extraText.trim().isEmpty()) {
                    sharedTextView.setText(sanitizeText(extraText));
                    sharedTextView.setVisibility(TextView.VISIBLE);
                }

                Log.d(TAG, "Received shared image content.");
            } else {
                showError("Failed to load the shared image.");
            }
        } catch (SecurityException e) {
            Log.e(TAG, "Security exception accessing shared image URI", e);
            showError("Permission denied when accessing the shared image.");
        } catch (Exception e) {
            Log.e(TAG, "Error loading shared image", e);
            showError("Error loading the shared image.");
        }
    }

    private Bitmap loadBitmapFromUri(Uri uri) {
        ParcelFileDescriptor parcelFileDescriptor = null;
        try {
            parcelFileDescriptor = getContentResolver().openFileDescriptor(uri, "r");
            if (parcelFileDescriptor == null) {
                return null;
            }
            FileDescriptor fileDescriptor = parcelFileDescriptor.getFileDescriptor();

            // First decode bounds to prevent loading excessively large images (OOM protection)
            BitmapFactory.Options options = new BitmapFactory.Options();
            options.inJustDecodeBounds = true;
            BitmapFactory.decodeFileDescriptor(fileDescriptor, null, options);

            // Calculate sample size for images larger than 2048x2048
            int maxDimension = 2048;
            options.inSampleSize = calculateInSampleSize(options, maxDimension, maxDimension);
            options.inJustDecodeBounds = false;

            // Re-open since the file descriptor position may have changed
            parcelFileDescriptor.close();
            parcelFileDescriptor = getContentResolver().openFileDescriptor(uri, "r");
            if (parcelFileDescriptor == null) {
                return null;
            }
            fileDescriptor = parcelFileDescriptor.getFileDescriptor();

            return BitmapFactory.decodeFileDescriptor(fileDescriptor, null, options);
        } catch (IOException e) {
            Log.e(TAG, "IOException loading bitmap from URI", e);
            return null;
        } finally {
            if (parcelFileDescriptor != null) {
                try {
                    parcelFileDescriptor.close();
                } catch (IOException e) {
                    Log.e(TAG, "Error closing ParcelFileDescriptor", e);
                }
            }
        }
    }

    private int calculateInSampleSize(BitmapFactory.Options options, int reqWidth, int reqHeight) {
        int height = options.outHeight;
        int width = options.outWidth;
        int inSampleSize = 1;

        if (height > reqHeight || width > reqWidth) {
            int halfHeight = height / 2;
            int halfWidth = width / 2;

            while ((halfHeight / inSampleSize) >= reqHeight
                    && (halfWidth / inSampleSize) >= reqWidth) {
                inSampleSize *= 2;
            }
        }
        return inSampleSize;
    }

    /**
     * Validates the URI to prevent intent hijacking and path traversal attacks.
     * Only content:// URIs are accepted as they go through the content provider
     * permission system. file:// URIs are rejected to prevent unauthorized file access.
     */
    private boolean isValidUri(Uri uri) {
        if (uri == null) {
            return false;
        }

        String scheme = uri.getScheme();
        if (scheme == null) {
            return false;
        }

        // Only allow content:// scheme - file:// URIs can be used for path traversal attacks
        if (!"content".equalsIgnoreCase(scheme)) {
            Log.w(TAG, "Rejected URI with untrusted scheme: " + scheme);
            return false;
        }

        // Check for path traversal attempts in the URI
        String path = uri.getPath();
        if (path != null && (path.contains("..") || path.contains("%2e%2e") || path.contains("%2E%2E"))) {
            Log.w(TAG, "Rejected URI with suspected path traversal: " + uri);
            return false;
        }

        return true;
    }

    /**
     * Sanitizes text input to prevent injection attacks.
     * Strips potentially dangerous characters and limits length.
     */
    private String sanitizeText(String input) {
        if (input == null) {
            return "";
        }

        // Limit text length to prevent memory issues
        int maxLength = 10000;
        String sanitized = input.length() > maxLength ? input.substring(0, maxLength) + "..." : input;

        // Remove null bytes which could cause issues
        sanitized = sanitized.replace("\0", "");

        return sanitized.trim();
    }

    private void showError(String message) {
        Toast.makeText(this, message, Toast.LENGTH_LONG).show();
        Log.w(TAG, message);

        contentTypeLabel.setText("Error");
        sharedTextView.setText(message);
        sharedTextView.setVisibility(TextView.VISIBLE);
        sharedImageView.setVisibility(ImageView.GONE);
    }
}